function a(e){return(e||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-zA-Z0-9 ]/g," ").trim().replace(/\s+/g,"-").toUpperCase()}function c(e,o,r=5){const i=(o||"").toUpperCase().replace(/[^A-Z0-9]/g,"");if(i)return i.slice(0,r);const t=(e||"").trim();if(!t)return"ORG";const s=t.split(/\s+/).filter(Boolean);if(s.length>=2){const n=s.slice(0,3).map(l=>l[0]||"").join("");if(n)return n.toUpperCase().slice(0,r)}return a(t).replace(/-/g,"").slice(0,Math.max(3,r))}export{c as m};
